// ================================================================
// STAGE 1: MESSAGE PARSER & COMMAND ROUTER
// Extracts message data, detects commands vs free text,
// builds conversation context
// ================================================================

const msg = $input.first().json.message;
const text = msg.text || '';
const chatId = msg.chat.id;
const userId = msg.from.id;
const userName = msg.from.first_name || 'User';
const userLang = msg.from.language_code || 'en';

// Detect message type
let messageType = 'support_request';
let command = null;
let payload = text;

if (text === '/start') {
  messageType = 'start';
} else if (text === '/help') {
  messageType = 'help';
} else if (text === '/status') {
  messageType = 'status';
} else if (text.startsWith('/feedback ')) {
  messageType = 'feedback';
  payload = text.replace('/feedback ', '');
} else if (text.length < 3) {
  messageType = 'too_short';
}

// Build ticket metadata
const ticket = {
  ticket_id: 'TK-' + Date.now(),
  message_type: messageType,
  raw_text: text,
  payload: payload,
  chat_id: chatId,
  user_id: userId,
  user_name: userName,
  user_language: userLang,
  message_length: text.length,
  has_url: /https?:\/\//.test(text),
  has_email: /[^\s@]+@[^\s@]+\.[^\s@]+/.test(text),
  has_phone: /[\d+()\-\s]{7,}/.test(text),
  word_count: text.split(/\s+/).filter(w => w.length > 0).length,
  created_at: new Date().toISOString()
};

return [{ json: ticket }];

