// ================================================================
// STAGE 2: PARSE CLASSIFICATION + ENRICH TICKET
// Merge AI classification with ticket metadata
// Compute SLA based on urgency + category
// ================================================================

const ticket = $('2. Message Parser').first().json;
const raw = $input.first().json;

let classification = {
  category: 'general_inquiry',
  urgency: 'medium',
  sentiment: 'neutral',
  requires_human: false,
  summary: ticket.raw_text.slice(0, 100),
  extracted_product: null,
  extracted_error: null,
  language: ticket.user_language
};

try {
  const content = raw.choices[0].message.content;
  const match = content.match(/\{[\s\S]*\}/);
  if (match) classification = JSON.parse(match[0]);
} catch(e) {}

// SLA MATRIX (minutes)
const slaMatrix = {
  critical: { billing: 30, technical: 15, bug_report: 15, complaint: 30, account: 30, feature_request: 120, general_inquiry: 60 },
  high: { billing: 60, technical: 30, bug_report: 30, complaint: 60, account: 60, feature_request: 240, general_inquiry: 120 },
  medium: { billing: 240, technical: 120, bug_report: 120, complaint: 240, account: 240, feature_request: 480, general_inquiry: 480 },
  low: { billing: 480, technical: 480, bug_report: 480, complaint: 480, account: 480, feature_request: 1440, general_inquiry: 1440 }
};

const urgency = classification.urgency || 'medium';
const category = classification.category || 'general_inquiry';
const slaMinutes = (slaMatrix[urgency] && slaMatrix[urgency][category]) || 480;

// Team assignment
const teamMap = {
  billing: 'finance_team',
  technical: 'tech_support_l2',
  account: 'account_management',
  feature_request: 'product_team',
  bug_report: 'engineering',
  complaint: 'customer_success',
  general_inquiry: 'support_l1'
};

const enriched = {
  ...ticket,
  ...classification,
  sla_minutes: slaMinutes,
  sla_deadline: new Date(Date.now() + slaMinutes * 60000).toISOString(),
  assigned_team: teamMap[category] || 'support_l1',
  priority_score: (classification.urgency === 'critical' ? 100 : classification.urgency === 'high' ? 75 : classification.urgency === 'medium' ? 50 : 25) + (classification.sentiment === 'angry' ? 20 : classification.sentiment === 'frustrated' ? 10 : 0)
};

return [{ json: enriched }];

