// Parse AI response
const ticket = $('6. Enrich & Compute SLA').first().json;
const raw = $input.first().json;

let autoReply = 'Thank you for reaching out. Your request has been received and a team member will follow up shortly.';
try { autoReply = raw.choices[0].message.content; } catch(e) {}

// Clean response for Telegram
autoReply = autoReply.replace(/[_*\[\]()~`>#+\-=|{}.!]/g, function(m) {
  if (m === '-' || m === '.') return m;
  return ' ';
});

return [{ json: { ...ticket, auto_reply: autoReply } }];

// ================================================================
// STAGE 3: BUILD CUSTOMER REPLY
// Format response for the user in Telegram
// ================================================================

const t = $input.first().json;

const urgencyEmoji = { critical: 'RED', high: 'ORANGE', medium: 'YELLOW', low: 'GREEN' };

const reply = t.auto_reply + '\n\n---\nTicket: ' + t.ticket_id + '\nCategory: ' + t.category + '\nPriority: ' + (t.urgency || 'medium').toUpperCase() + '\nTeam: ' + t.assigned_team + '\n\nA human agent will review within ' + t.sla_minutes + ' minutes if needed.';

return [{ json: { ...t, customer_reply: reply } }];

// FEEDBACK HANDLER
const ticket = $input.first().json;
const feedbackMsg = 'Thank you for your feedback, ' + ticket.user_name + '. We have recorded it and our team will review it.\n\nYour feedback: "' + ticket.payload.slice(0, 200) + '"';

return [{ json: { chat_id: ticket.chat_id, reply: feedbackMsg, ticket_id: ticket.ticket_id, skip_ai: true } }];
